-- Set tenantId for NVC360 admin users (tenantId = NULL = platform-level)
UPDATE users SET tenantId = NULL, role = 'super_admin' WHERE email IN ('admin@nvc360.com', 'pm@nvc360.com');

-- Set tenantId for Acme HVAC users (tenant 1 based on seed data)
UPDATE users SET tenantId = (SELECT id FROM tenants WHERE slug = 'acme-hvac' LIMIT 1), role = 'merchant_manager'
  WHERE email = 'dispatch@acmehvac.com';

UPDATE users SET tenantId = (SELECT id FROM tenants WHERE slug = 'acme-hvac' LIMIT 1), role = 'agent'
  WHERE email = 'tech@acmehvac.com';

-- Set tenantId for PlumbPro users
UPDATE users SET tenantId = (SELECT id FROM tenants WHERE slug = 'plumb-pro' LIMIT 1), role = 'merchant_manager'
  WHERE email = 'admin@plumbpro.com';

